// Extract event data from webhook payload
const payload = $input.first().json;
const isCropEvent = payload.body?.event_type?.startsWith('crop');
const isRiskEvent = payload.body?.event_type === 'risk_evaluation';

const event = payload.body || payload;

// Build context for LLM
let context = '';
if (isCropEvent) {
  context = `Crop Health Event:
- Parcel: ${event.parcel_id || 'unknown'}
- CWSI: ${event.cwsi || 'N/A'}
- MDS Severity: ${event.mds_severity || 'N/A'}
- Water Balance: ${event.water_balance_mm || 'N/A'}mm
- Overall Severity: ${event.overall_severity || 'unknown'}
- Recommended Action: ${event.recommended_action || 'none'}
- Phenology Source: ${event.phenology_source || 'default'}
- Timestamp: ${event.timestamp || ''}`;
} else if (isRiskEvent) {
  context = `Risk Evaluation Event:
- Entity: ${event.entity_id || 'unknown'}
- Risk Code: ${event.risk_code || 'unknown'}
- Probability: ${event.probability_score || 0}%
- Severity: ${event.severity || 'low'}
- Timestamp: ${event.timestamp || ''}`;
} else {
  context = JSON.stringify(event, null, 2);
}

return {
  tenant_id: event.tenant_id || '',
  parcel_id: event.parcel_id || event.entity_id || '',
  severity: event.overall_severity || event.severity || 'low',
  context: context,
  raw: event
};

const item = $input.first().json;
const severity = item.severity?.toLowerCase() || 'low';

// Only analyze HIGH or CRITICAL events
if (severity !== 'high' && severity !== 'critical') {
  return { skip: true, reason: 'Severity below threshold' };
}

return item;

const item = $input.first().json;

// Build the LLM prompt
return {
  systemPrompt: `Eres un experto agrónomo analizando datos de salud de cultivo en tiempo real para agricultores.

Analiza el siguiente evento y proporciona:
1. Interpretación en lenguaje claro y sencillo para el agricultor
2. Contexto agronómico adicional (¿qué significa este valor para este cultivo?)
3. Recomendación concreta, priorizada y accionable
4. Si es crítico, indica la urgencia y las posibles consecuencias de no actuar

Responde en ESPAÑOL. Tono profesional pero cercano. Máximo 3 párrafos. Formatea para Zulip (usa **negrita** y saltos de línea).`,
  userMessage: item.context
};

const llmResponse = $input.first().json;
const eventData = $('Parse Event').first().json;

return {
  tenant_id: eventData.tenant_id,
  parcel_id: eventData.parcel_id,
  severity: eventData.severity,
  analysis: llmResponse.content || JSON.stringify(llmResponse),
  timestamp: new Date().toISOString()
};
